existing = {p["id"] for p in data["prompts"]}
new = [p for p in batch if p["id"] not in existing]
data["prompts"].extend(new)

with open("data/prompts.json","w", encoding="utf-8") as f:
    json.dump(data, f, indent=2, ensure_ascii=False)

